import{_ as r,o as t,c as p,j as e,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"皇帝弗提格雷的摇摆沙发床","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/7.载具及随从/载具/1.D级/皇帝弗提格雷的摇摆沙发床.md","filePath":"4.资源分区/7.物品与装备/7.载具及随从/载具/1.D级/皇帝弗提格雷的摇摆沙发床.md"}'),_={name:"4.资源分区/7.物品与装备/7.载具及随从/载具/1.D级/皇帝弗提格雷的摇摆沙发床.md"};function o(d,a,l,i,b,c){return t(),p("div",null,[...a[0]||(a[0]=[e("h1",{id:"皇帝弗提格雷的摇摆沙发床",tabindex:"-1"},[n("皇帝弗提格雷的摇摆沙发床 "),e("a",{class:"header-anchor",href:"#皇帝弗提格雷的摇摆沙发床","aria-label":'Permalink to "皇帝弗提格雷的摇摆沙发床"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌035")])])],-1),s('<h1 id="皇帝弗提格雷的摇摆沙发床-1" tabindex="-1">皇帝弗提格雷的摇摆沙发床 <a class="header-anchor" href="#皇帝弗提格雷的摇摆沙发床-1" aria-label="Permalink to &quot;皇帝弗提格雷的摇摆沙发床&quot;">​</a></h1><p>皇帝弗提格雷的摇摆沙发床 <br> 价格：D+700<br> 重量：100磅<br> 载具本质：魔幻本质 <br> 载具类型：轻型载具 <br> 载具专业：轻型载具</p><p>这张华贵的红色毛毡沙发床的边缘装饰着金色的网格，制成它的黑木也已经被高度抛光，显得很有光泽。在你躺上去之后，你将会自动理解该如何激活它。这张在数千年前为塔尔多疯王弗提格雷制造出来的摇摆沙发床有着很多特殊的能力。</p><p>速度：40米</p><p>转弯半径：以一个移动动作可原地转向90度；或包含在距离不少于50米的移动中。</p><p>生存能力：</p><p>体积：7</p><p>结构值：16　装甲值：12</p><p>最大载员：2人（躺）</p><p>每天需要支付1点任意能量，维持皇帝弗提格雷的摇摆沙发床的正常消耗<br> ==========特殊能力===========<br> 无动作要素操作：<br> 当使用者坐、站或者是躺在上面时，它能漂浮起来距离地面20cm，这可以视为笨拙飞行，像是气垫船一样以40米的速度移动，操作摇摆沙发床无需动作要素。</p><p>环境免疫<br> 沙发的两侧扶手可以翻开变成托盘，这两个扶手每天制造出足够两名成年男性饮用的普通饮料，并生成一个小的魔法力场，它无法用来阻挡伤害，但可以用于阻挡风沙，紫外线，可以在-50至+50摄氏度的温度下正常工作，为使用者和乘坐者提供舒适的环境，这视为沙发为载员提供D级的免疫环境效果。<br> 皇帝弗提格雷的摇摆沙发床 <br> 摇摆沙发床自带华丽的抱枕和靠垫，你可以在将摇摆沙发床从载具胶囊中取出时，自由决定这些附加物的样子，但这些附加物都不能离开沙发床，否则会自动消失。附加物可以包括抱枕、靠垫和毯子，附加物默认均是崭新的，但是你也可以决定使用更旧些的，当使用者在床上休息时，因为舒适奢华的环境，进行长休息时的需求时间减半。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',13)])])}const m=r(_,[["render",o]]);export{f as __pageData,m as default};
